import java.util.*;

public class MultiProfileConfig {
    private Map<String, String> base = new LinkedHashMap<>();
    private Map<String, String> override = new LinkedHashMap<>();

    public void loadBase(Map<String, String> baseProps) {
        this.base.putAll(baseProps);
    }

    public void loadProfile(Map<String, String> profileProps) {
        this.override.putAll(profileProps);
    }

    public String get(String key) {
        // TODO: Return override value if exists, else base value, else null
        return null;
    }

    public Map<String, String> getEffectiveConfig() {
        // TODO: Merge base with override (override wins)
        return new LinkedHashMap<>();
    }
}

public class Main {
    public static void main(String[] args) {
        Map<String, String> baseProps = new LinkedHashMap<>();
        baseProps.put("server.port", "8080");
        baseProps.put("app.name", "MyApp");
        baseProps.put("logging.level", "INFO");
        baseProps.put("db.url", "jdbc:h2:mem:testdb");

        Map<String, String> devProps = new LinkedHashMap<>();
        devProps.put("logging.level", "DEBUG");  // overrides base
        devProps.put("db.url", "jdbc:postgresql://localhost/devdb");  // overrides base
        devProps.put("debug.enabled", "true");  // new in dev

        MultiProfileConfig config = new MultiProfileConfig();
        config.loadBase(baseProps);
        config.loadProfile(devProps);

        System.out.println("Effective configuration (dev profile):");
        config.getEffectiveConfig().forEach((k, v) -> System.out.println("  " + k + " = " + v));
    }
}

